let chartInstances={};let currentData={scores:[],metrics:[],ranking:[],alerts:[],historique:[]};async function initializeDashboard(){console.log('🚀 Initializing KPI Dashboard...');showLoading(true);try{await loadMetrics();await loadScores();await loadRanking();await loadAlerts();await loadHistorique();updateStatsOverview();renderMetricCards();renderCharts();renderRankingTables();renderAlerts();console.log('✅ Dashboard initialized successfully');}catch(error){console.error('❌ Error initializing dashboard:',error);showError('Erreur lors du chargement du dashboard');}finally{showLoading(false);}}async function loadMetrics(){try{const response=await fetch('/api/kpi/metrics');if(!response.ok)throw new Error('Failed to load metrics');const result=await response.json();currentData.metrics=result.data||[];console.log('✅ Loaded metrics:',currentData.metrics.length);}catch(error){console.error('❌ Error loading metrics:',error);}}async function loadScores(){try{const filters=new URLSearchParams();const techId=document.getElementById('filterTechnicien')?.value;const equipeId=document.getElementById('filterEquipe')?.value;if(techId)filters.append('technicien_id',techId);if(equipeId)filters.append('equipe_id',equipeId);const response=await fetch(`/api/kpi/scores?${filters}`);if(!response.ok)throw new Error('Failed to load scores');const result=await response.json();currentData.scores=result.data||[];console.log('✅ Loaded scores:',currentData.scores.length);}catch(error){console.error('❌ Error loading scores:',error);}}async function loadRanking(){try{const response=await fetch('/api/kpi/ranking');if(!response.ok)throw new Error('Failed to load ranking');const result=await response.json();currentData.ranking=result.data||[];console.log('✅ Loaded ranking:',currentData.ranking.length);}catch(error){console.error('❌ Error loading ranking:',error);}}async function loadAlerts(){try{const response=await fetch('/api/kpi/alertes?statut=active');if(!response.ok)throw new Error('Failed to load alerts');const result=await response.json();currentData.alerts=result.data||[];console.log('✅ Loaded alerts:',currentData.alerts.length);}catch(error){console.error('❌ Error loading alerts:',error);}}async function loadHistorique(){try{if(currentData.scores.length>0){const techId=currentData.scores[0].technicien_id;const response=await fetch(`/api/kpi/scores/${techId}/historique`);if(!response.ok)throw new Error('Failed to load historique');const result=await response.json();currentData.historique=result.data||[];console.log('✅ Loaded historique:',currentData.historique.length);}}catch(error){console.error('❌ Error loading historique:',error);}}function updateStatsOverview(){if(currentData.scores.length===0)return;const scores=currentData.scores.map(s=>s.scores.total).filter(s=>s!==null&&s!==undefined);const avgScore=scores.length>0 ?(scores.reduce((a,b)=>a+b,0)/scores.length).toFixed(1):0;const bestScore=scores.length>0 ? Math.max(...scores).toFixed(1):0;const alertCount=currentData.alerts.length;const anomalyCount=currentData.scores.filter(s=>s.etat.anomalie).length;document.getElementById('avgScore').textContent=avgScore;document.getElementById('bestScore').textContent=bestScore;document.getElementById('alertCount').textContent=alertCount;document.getElementById('anomalyCount').textContent=anomalyCount;document.getElementById('statsContainer').style.display='grid';}function renderMetricCards(){const container=document.getElementById('metricsContainer');if(!container){console.error('❌ metricsContainer not found in DOM');return;}if(currentData.metrics.length===0){container.innerHTML='<p class="text-center text-muted">Aucune métrique disponible</p>';return;}const html=currentData.metrics.map((metric,idx)=>{const score=calculateMetricAverage(metric.nom);const status=getScoreStatus(score,metric.seuil_alerte);return `<div class="metric-card score-${(idx % 5)+1}"><div class="metric-header"><h3 class="metric-name">${metric.description||metric.nom}</h3><span class="metric-weight">${(metric.poids*100).toFixed(0)}%</span></div><div class="metric-value">${score ? score.toFixed(1):'N/A'}</div><div class="metric-details"><div class="detail-item"><p class="detail-label">Seuil</p><p class="detail-value">${metric.seuil_alerte||metric.seuil_max}</p></div><div class="detail-item"><p class="detail-label">Min</p><p class="detail-value">${metric.seuil_min}</p></div><div class="detail-item"><p class="detail-label">Max</p><p class="detail-value">${metric.seuil_max}</p></div><div class="detail-item"><p class="detail-label">Statut</p><p class="detail-value ${status.class}">${status.icon}</p></div><div class="detail-item"><p class="detail-label">Unité</p><p class="detail-value">${metric.unite}</p></div></div></div>`;}).join('');container.innerHTML=html;}function renderCharts(){if(currentData.scores.length===0){document.getElementById('chartsContainer').style.display='none';return;}document.getElementById('chartsContainer').style.display='grid';renderTrendChart();renderRankingChart();renderDistributionChart();renderMetricsChart();}function renderTrendChart(){const ctx=document.getElementById('trendChart');if(!ctx)return;const labels=currentData.historique.slice(-30).map(h=>{const date=new Date(h.date);return(date.getMonth()+1)+'/'+date.getDate();});const datasets=[{label:'Score Total',data:currentData.historique.slice(-30).map(h=>h.score_total),borderColor:'#667eea',backgroundColor:'rgba(102,126,234,0.1)',tension:0.4,fill:true,borderWidth:3},{label:'1ère Visite',data:currentData.historique.slice(-30).map(h=>h.score_resolution_1ere_visite),borderColor:'#764ba2',backgroundColor:'rgba(118,75,162,0.1)',tension:0.4,fill:false,borderWidth:2},{label:'SLA',data:currentData.historique.slice(-30).map(h=>h.score_respect_sla),borderColor:'#f093fb',backgroundColor:'rgba(240,147,251,0.1)',tension:0.4,fill:false,borderWidth:2}];if(chartInstances.trend)chartInstances.trend.destroy();chartInstances.trend=new Chart(ctx,{type:'line',data:{labels:labels,datasets:datasets},options:{responsive:true,maintainAspectRatio:true,plugins:{legend:{position:'bottom',labels:{usePointStyle:true,padding:20,font:{size:12,weight:'bold'}}}},scales:{y:{beginAtZero:true,max:100,ticks:{font:{size:11}}},x:{ticks:{font:{size:11}}}}}});}function renderRankingChart(){const ctx=document.getElementById('rankingChart');if(!ctx||currentData.ranking.length===0)return;const topPerformers=currentData.ranking.slice(0,10);if(chartInstances.ranking)chartInstances.ranking.destroy();chartInstances.ranking=new Chart(ctx,{type:'bar',data:{labels:topPerformers.map(r=>r.technicien||'Unknown'),datasets:[{label:'Score Total',data:topPerformers.map(r=>r.score_total),backgroundColor:topPerformers.map((_,i)=>{const colors=['#667eea','#764ba2','#f093fb','#4facfe','#43e97b','#ffd700','#ff6b6b'];return colors[i % colors.length];}),borderRadius:5,borderSkipped:false}]},options:{indexAxis:'y',responsive:true,maintainAspectRatio:true,plugins:{legend:{display:false}},scales:{x:{beginAtZero:true,max:100,ticks:{font:{size:11}}},y:{ticks:{font:{size:11}}}}}});}function renderDistributionChart(){const ctx=document.getElementById('distributionChart');if(!ctx)return;const scores=currentData.scores.map(s=>s.scores.total).filter(s=>s!==null);const buckets={'Excellent(90+)':scores.filter(s=>s>=90).length,'Très Bon(80-89)':scores.filter(s=>s>=80&&s<90).length,'Bon(70-79)':scores.filter(s=>s>=70&&s<80).length,'À Améliorer(60-69)':scores.filter(s=>s>=60&&s<70).length,'Critique(<60)':scores.filter(s=>s<60).length};if(chartInstances.distribution)chartInstances.distribution.destroy();chartInstances.distribution=new Chart(ctx,{type:'doughnut',data:{labels:Object.keys(buckets),datasets:[{data:Object.values(buckets),backgroundColor:['#43e97b','#4facfe','#ffd700','#ffa94d','#ff6b6b'],borderColor:['#fff','#fff','#fff','#fff','#fff'],borderWidth:3}]},options:{responsive:true,maintainAspectRatio:true,plugins:{legend:{position:'bottom',labels:{padding:20,font:{size:12,weight:'bold'}}}}}});}function renderMetricsChart(){const ctx=document.getElementById('metricsChart');if(!ctx||currentData.metrics.length===0)return;const metricAverages=currentData.metrics.map(m=>({name:m.nom.replace(/_/g,' '),average:calculateMetricAverage(m.nom),threshold:m.seuil_alerte}));if(chartInstances.metrics)chartInstances.metrics.destroy();chartInstances.metrics=new Chart(ctx,{type:'radar',data:{labels:metricAverages.map(m=>m.name),datasets:[{label:'Moyenne Actuelle',data:metricAverages.map(m=>m.average),borderColor:'#667eea',backgroundColor:'rgba(102,126,234,0.2)',borderWidth:2,pointRadius:5,pointBackgroundColor:'#667eea'},{label:'Seuil Alerte',data:metricAverages.map(m=>m.threshold),borderColor:'#ff6b6b',backgroundColor:'rgba(255,107,107,0.1)',borderWidth:2,borderDash:[5,5],pointRadius:4,pointBackgroundColor:'#ff6b6b'}]},options:{responsive:true,maintainAspectRatio:true,plugins:{legend:{position:'bottom',labels:{padding:20,font:{size:12,weight:'bold'}}}},scales:{r:{beginAtZero:true,max:100,ticks:{font:{size:10}}}}}});}function renderRankingTables(){if(currentData.ranking.length===0)return;document.getElementById('rankingCard').style.display='block';document.getElementById('bottomPerformersCard').style.display='block';const topPerformers=currentData.ranking.slice(0,10);const bottomPerformers=currentData.ranking.slice(-5).reverse();const topHtml=topPerformers.map((r,idx)=>`<tr onclick="showTechnicianDetails(${r.technicien_id})"><td><span class="rank-badge">#${idx+1}</span></td><td><strong>${r.technicien||'N/A'}</strong></td><td>${r.equipe||'N/A'}</td><td><strong>${(r.score_total||0).toFixed(1)}</strong></td><td>${getTrendIcon(r.tendance)}</td><td><span class="alert-badge alert-${getAlertLevel(r.score_total)}">${getScoreStatus(r.score_total).icon}</span></td><td><button class="btn-details btn-sm" onclick="event.stopPropagation();showTechnicianDetails(${r.technicien_id})"><i class="feather" data-feather="eye"></i>Détails</button></td></tr>`).join('');document.getElementById('rankingTableBody').innerHTML=topHtml;const bottomHtml=bottomPerformers.map((r,idx)=>{const alertCount=currentData.alerts.filter(a=>a.technicien_id===r.technicien_id&&a.active).length;return `<tr onclick="showTechnicianDetails(${r.technicien_id})"><td><span class="rank-badge" style="background:#ff6b6b;">⚠️ #${currentData.ranking.length-idx}</span></td><td><strong>${r.technicien||'N/A'}</strong></td><td>${r.equipe||'N/A'}</td><td><strong style="color:#ff6b6b;">${(r.score_total||0).toFixed(1)}</strong></td><td>${getTrendIcon(r.tendance)}</td><td><strong>${alertCount}alerte(s)</strong></td><td><button class="btn-details btn-sm" onclick="event.stopPropagation();showTechnicianDetails(${r.technicien_id})"><i class="feather" data-feather="arrow-right"></i>Voir</button></td></tr>`;}).join('');document.getElementById('bottomTableBody').innerHTML=bottomHtml;}function renderAlerts(){const container=document.getElementById('alertsList');if(currentData.alerts.length===0){document.getElementById('alertsContainer').style.display='none';return;}document.getElementById('alertsContainer').style.display='block';const alertHtml=currentData.alerts.map(alert=>`<div class="alert-card ${alert.severite}"><div class="alert-info"><p class="alert-title">${alert.titre}</p><p class="alert-description">${alert.description}</p><p class="alert-metric">Métrique:<strong>${alert.metrique}</strong></p></div><div class="alert-actions"><button class="btn-details btn-sm" onclick="showAlertDetails(${alert.id})"><i class="feather" data-feather="info"></i>Détails</button><button class="btn-resolve btn-sm" onclick="resolveAlert(${alert.id})"><i class="feather" data-feather="check"></i>Résoudre</button></div></div>`).join('');container.innerHTML=alertHtml;}async function showTechnicianDetails(technicianId){const modal=document.getElementById('detailModal');const modalBody=document.getElementById('modalBody');const modalTitle=document.getElementById('modalTitle');try{const response=await fetch(`/api/kpi/scores/${technicianId}`);if(!response.ok)throw new Error('Failed to load technician details');const result=await response.json();const data=result.data;const histResponse=await fetch(`/api/kpi/scores/${technicianId}/historique`);const histData=await histResponse.json();modalTitle.textContent=`📊 Détails-${data.technicien}`;const scores=data.scores;const alerts=currentData.alerts.filter(a=>a.technicien_id===technicianId&&a.active);let html=`<div class="row"><div class="col-md-6"><div class="metric-card" style="background:#f9f9f9;border-left:5px solid #667eea;"><h5>Score Total</h5><p style="font-size:36px;font-weight:700;color:#667eea;">${(scores.total||0).toFixed(1)}</p></div></div><div class="col-md-6"><div class="metric-card" style="background:#f9f9f9;border-left:5px solid #764ba2;"><h5>Équipe</h5><p style="font-size:20px;font-weight:700;">${data.equipe}</p></div></div></div><div style="margin-top:20px;"><h5>📊 Détail des Scores</h5><div class="row">`;const metricNames=[{key:'resolution_1ere_visite',label:'1ère Visite',color:'#667eea'},{key:'respect_sla',label:'Respect SLA',color:'#764ba2'},{key:'qualite_rapports',label:'Qualité Rapports',color:'#f093fb'},{key:'satisfaction_client',label:'Satisfaction',color:'#4facfe'},{key:'consommation_stock',label:'Stock',color:'#43e97b'}];metricNames.forEach(m=>{const value=scores[m.key];html+=`<div class="col-md-6"><div style="background:white;padding:15px;border-radius:8px;border-left:4px solid ${m.color};margin-bottom:10px;"><p style="margin:0;color:#666;font-size:12px;text-transform:uppercase;">${m.label}</p><p style="margin:5px 0 0 0;font-size:24px;font-weight:700;color:${m.color};">${(value||0).toFixed(1)}</p></div></div>`;});html+=`</div></div>`;if(data.objectifs){html+=`<div style="margin-top:20px;"><h5>🎯 Objectifs 2026</h5><div class="row">`;metricNames.forEach(m=>{const objKey=`objectif_${m.key}`;const value=data.objectifs[objKey];html+=`<div class="col-md-6"><p style="margin:5px 0;font-size:13px;color:#666;">${m.label}:<strong>${value}%</strong></p></div>`;});html+=`</div></div>`;}if(alerts.length>0){html+=`<div style="margin-top:20px;"><h5>⚠️ Alertes Actives(${alerts.length})</h5>`;alerts.forEach(alert=>{html+=`<div class="alert-card ${alert.severite}" style="margin-bottom:10px;"><div class="alert-info"><p class="alert-title">${alert.titre}</p><p class="alert-description">${alert.description}</p></div></div>`;});html+=`</div>`;}if(alerts.length>0&&alerts[0].recommandations){const recommendations=alerts[0].recommandations;if(Array.isArray(recommendations)&&recommendations.length>0){html+=`<div class="recommendation"><p class="recommendation-title">💡 Recommandations d'Amélioration</p><ul class="recommendation-list">${recommendations.map(r=>`<li>${r}</li>`).join('')}</ul></div>`;}}if(histData.data&&histData.data.length>0){html+=`<div class="detail-chart"><h5>📈 Historique(30 jours)</h5><canvas id="technicianDetailChart"></canvas></div>`;}modalBody.innerHTML=html;modal.style.display='block';if(histData.data&&histData.data.length>0){setTimeout(()=>renderTechnicianDetailChart(histData.data),100);}}catch(error){console.error('Error loading technician details:',error);modalBody.innerHTML='<p class="text-danger">Erreur lors du chargement des détails</p>';modal.style.display='block';}}function renderTechnicianDetailChart(historique){const ctx=document.getElementById('technicianDetailChart');if(!ctx)return;const labels=historique.slice(-30).map(h=>{const date=new Date(h.date);return(date.getMonth()+1)+'/'+date.getDate();});const data={labels:labels,datasets:[{label:'Score Total',data:historique.slice(-30).map(h=>h.score_total),borderColor:'#667eea',backgroundColor:'rgba(102,126,234,0.1)',tension:0.4,fill:true,borderWidth:3}]};new Chart(ctx,{type:'line',data:data,options:{responsive:true,plugins:{legend:{display:true}},scales:{y:{beginAtZero:true,max:100}}}});}function showAlertDetails(alertId){const alert=currentData.alerts.find(a=>a.id===alertId);if(!alert)return;const modal=document.getElementById('detailModal');const modalBody=document.getElementById('modalBody');const modalTitle=document.getElementById('modalTitle');modalTitle.textContent=`⚠️ ${alert.titre}`;let html=`<div style="background:#f9f9f9;padding:20px;border-radius:8px;margin-bottom:20px;border-left:5px solid #ff6b6b;"><p><strong>Type:</strong>${alert.type}</p><p><strong>Sévérité:</strong><span class="alert-badge alert-${alert.severite}">${alert.severite.toUpperCase()}</span></p><p><strong>Métrique:</strong>${alert.metrique}</p><p><strong>Créée:</strong>${new Date(alert.date_creation).toLocaleString('fr-FR')}</p></div><h5>Description</h5><p>${alert.description}</p><div style="margin-top:20px;padding:15px;background:#f5f5f5;border-radius:8px;"><p><strong>Valeur Actuelle:</strong>${(alert.valeur_actuelle||0).toFixed(2)}</p><p><strong>Seuil:</strong>${(alert.valeur_seuil||0).toFixed(2)}</p></div>`;if(alert.recommandations&&Array.isArray(alert.recommandations)&&alert.recommandations.length>0){html+=`<div class="recommendation"><p class="recommendation-title">💡 Actions Recommandées</p><ul class="recommendation-list">${alert.recommandations.map(r=>`<li>${r}</li>`).join('')}</ul></div>`;}html+=`<div style="margin-top:20px;"><button class="btn btn-success" onclick="resolveAlert(${alert.id})"><i class="feather" data-feather="check"></i>Marquer comme Résolu</button></div>`;modalBody.innerHTML=html;modal.style.display='block';}async function resolveAlert(alertId){try{const response=await fetch(`/api/kpi/alertes/${alertId}/resolve`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({note:'Résolu depuis le dashboard'})});if(!response.ok)throw new Error('Failed to resolve alert');currentData.alerts=currentData.alerts.filter(a=>a.id!==alertId);renderAlerts();closeModal();showSuccess('Alerte résolue avec succès');}catch(error){console.error('Error resolving alert:',error);showError('Erreur lors de la résolution de l\'alerte');}}function closeModal(){document.getElementById('detailModal').style.display='none';}function applyFilters(){initializeDashboard();}function calculateMetricAverage(metricName){const scores=currentData.scores .map(s=>s.scores[metricName.replace(/_/g,'_')]).filter(s=>s!==null&&s!==undefined);if(scores.length===0)return 0;return scores.reduce((a,b)=>a+b,0)/scores.length;}function getScoreStatus(score,threshold=75){if(score===null||score===undefined){return{icon:'❓',class:'text-muted'};}if(score>=(threshold||75)){return{icon:'✅',class:'text-success'};}else if(score>=60){return{icon:'⚠️',class:'text-warning'};}else{return{icon:'❌',class:'text-danger'};}}function getTrendIcon(trend){switch(trend){case 'hausse':return '<span class="trending-up">📈 Hausse</span>';case 'baisse':return '<span class="trending-down">📉 Baisse</span>';default:return '<span class="trending-stable">➡️ Stable</span>';}}function getAlertLevel(score){if(score>=80)return 'low';if(score>=70)return 'medium';if(score>=60)return 'high';return 'critical';}function showLoading(show){document.getElementById('loadingState').style.display=show ? 'block':'none';}function showError(message){alert('❌ '+message);}function showSuccess(message){console.log('✅ '+message);}window.onclick=function(event){const modal=document.getElementById('detailModal');if(event.target==modal){modal.style.display='none';}};